xf:var.value:
exists(
    xbl:binding[
        not(
            fb:metadata/fb:toolbox[@show = 'false']
        ) and
            xxf:has-class('fr-section-component', .)
    ]
)

xf:output.value:
$form-resources/library-dialog/(
    if ($search-total = 0) then none else if ($search-total = 1) then one else several
)/label
